dslRule:
/*!id: suppresswarnings-single-to-array*/
/*!description: Wrap single String literal in @SuppressWarnings into an array literal for consistent style*/
/*!severity: info*/
/*!minJavaVersion: 8*/
/*!tags: annotations, style*/

@java.lang.SuppressWarnings($arg) :: isLiteral($arg) && $arg instanceof java.lang.String
=> @java.lang.SuppressWarnings({$arg})
;;

new java.lang.Byte($val)
=> java.lang.Byte.valueOf($val)
;;

new java.lang.Short($val)
=> java.lang.Short.valueOf($val)
;;

new java.lang.Character($val)
=> java.lang.Character.valueOf($val)
;;
